def flushMappedBufferRange(buffer: Buffer, offset: int, length: int, read: bool, write: bool, invalidate: bool):
    if invalidate:
        buffer.preserve_range(offset, length)

    if read and write:
        buffer.read_write_range(offset, length)
    elif read:
        buffer.read_range(offset, length)
    elif write:
        buffer.write_range(offset, length)

    buffer.flush_range(offset, length)

