def top_students(marks, n):
    sorted_students = sorted(marks.items(), key=lambda x: (-x[1], x[0]))
    top_n_students = []
    count = 0
    while count < n and sorted_students:
        current_score = sorted_students[0][1]
        while sorted_students and sorted_students[0][1] == current_score:
            top_n_students.append(sorted_students.pop(0)[0])
            count += 1
    return top_n_students

