import hashlib

class HeapObjectFactory:
    pass

class KvpHeapObjectFactory(HeapObjectFactory):
    def __init__(self, obj, options=None):
        self._items = obj
        self._object_id = self._generate_object_id()
        self._max_len = options.get('max_size', len(self._items)) if options else len(self._items)
        self._render_options = options.get('render_options') if options else None

    def _generate_object_id(self):
        sorted_items = sorted(self._items.items())
        hash_object = hashlib.sha256()
        for key, value in sorted_items:
            hash_object.update(str(key).encode())
            hash_object.update(str(value).encode())
        return hash_object.hexdigest()

