from http.server import BaseHTTPRequestHandler, HTTPServer
import threading

class JsonEncoder:
    def __init__(self, head):
        self.head = head

    def encode(self, content):
        return '<!DOCTYPE html><html><head>' + self.head + '</head><body>' + str(content) + '</body></html>'

class MyHandler(BaseHTTPRequestHandler):
    def respond(self, status_code, content, encoder):
        encoded_content = encoder.encode(content)
        self.send_response(status_code)
        self.send_header('Content-type', 'text/html')
        self.end_headers()
        self.wfile.write(encoded_content.encode('utf-8'))

    def do_GET(self):
        if self.path in self.server.response_cache:
            self.respond(200, self.server.response_cache[self.path], self.server.encoder)
        else:
            self.respond(404, "Not Found", self.server.encoder)

def run_server(info, port, encoder=None, response_cache={}):
    if encoder is None:
        encoder = JsonEncoder(head="Default Head")

    class CustomHTTPServer(HTTPServer):
        def __init__(self, server_address, RequestHandlerClass, encoder, response_cache):
            super().__init__(server_address, RequestHandlerClass)
            self.encoder = encoder
            self.response_cache = response_cache

    server_address = ('', port)
    httpd = CustomHTTPServer(server_address, MyHandler, encoder, response_cache)
    print(f"Starting httpd server on {info} at port {port}")
    httpd.serve_forever()

