import time
import threading

class TrafficLight:
    def __init__(self):
        self.states = ["red", "green", "yellow"]
        self.state_durations = {"red": 30, "green": 60, "yellow": 10}
        self.current_state = "red"
        self.remaining_time = self.state_durations[self.current_state]

    def switch_state(self):
        current_index = self.states.index(self.current_state)
        next_index = (current_index + 1) % len(self.states)
        self.current_state = self.states[next_index]
        self.remaining_time = self.state_durations[self.current_state]

    def get_current_state(self):
        return self.current_state

    def get_remaining_time(self):
        return self.remaining_time

    def update_time(self):
        self.remaining_time -= 1
        if self.remaining_time == 0:
            self.switch_state()

class TrafficControlSystem:
    def __init__(self):
        self.traffic_lights = []
        self.running = False

    def add_traffic_light(self):
        self.traffic_lights.append(TrafficLight())

    def start_simulation(self):
        self.running = True
        self.simulation_thread = threading.Thread(target=self._run_simulation)
        self.simulation_thread.start()

    def stop_simulation(self):
        self.running = False
        self.simulation_thread.join()

    def _run_simulation(self):
        while self.running:
            for traffic_light in self.traffic_lights:
                print(f"Traffic Light: {traffic_light.get_current_state()}, Remaining Time: {traffic_light.get_remaining_time()} seconds")
                traffic_light.update_time()
            time.sleep(1)

