def can_visit_all_rooms(rooms: dict) -> bool:
    visited = set()
    stack = [0]

    while stack:
        room = stack.pop()
        if room not in visited:
            visited.add(room)
            stack.extend(rooms[room])

    return len(visited) == len(rooms)

