def max_subarray_sum(input_list):
    if not input_list:
        return 0

    max_ending_here = max_so_far = input_list[0]

    for x in input_list[1:]:
        max_ending_here = max(x, max_ending_here + x)
        max_so_far = max(max_so_far, max_ending_here)

    return max_so_far

from typing import List

def compute_median(arr: List[int]) -> float:
    arr.sort()
    n = len(arr)
    if n % 2 == 1:
        return float(arr[n // 2])
    else:
        return (arr[n // 2 - 1] + arr[n // 2]) / 2.0

import re

def extract_details(snippet):
    details = {
        'author': None,
        'description': None,
        'url': None
    }

    author_match = re.search(r'author\s*=\s*[\'\"]([^\'\"]+)[\'\"]', snippet)
    description_match = re.search(r'description\s*=\s*[\'\"]([^\'\"]+)[\'\"]', snippet)
    url_match = re.search(r'url\s*=\s*[\'\"]([^\'\"]+)[\'\"]', snippet)

    if author_match:
        details['author'] = author_match.group(1)
    if description_match:
        details['description'] = description_match.group(1)
    if url_match:
        details['url'] = url_match.group(1)

    return details

