def get_creator_count(filename):
    data = read_json_file(filename)
    if data:
        creator_count = {}
        for language in data:
            creator = language['creator']
            if creator in creator_count:
                creator_count[creator] += 1
            else:
                creator_count[creator] = 1
        return creator_count
    return None

def get_languages_by_year(filename, year):
    data = read_json_file(filename)
    if data:
        languages_by_year = [language['name'] for language in data if language['year'] == year]
        return languages_by_year
    return None

