def shuffle_files(files: List[str]) -> AudioIODataset:
    random.shuffle(files)
    data = []
    labels = []

    for file in files:
        try:
            audio_data = np.load(file)  # Assuming the audio data is stored in .npy format
            label = file.split('/')[-1].split('.')[0]  # Extracting label from filename
            data.append(audio_data)
            labels.append(label)
        except Exception as e:
            print(f"Error loading file {file}: {e}")

    return AudioIODataset(data, labels)

