import torch.nn as nn
import torch

def create_neural_block(out_filters, bn=True, gaussian_kernel=None):
    block = [
        nn.LeakyReLU(0.2, inplace=True),
        nn.Dropout3d(0.25)
    ]

    if bn:
        block.append(nn.BatchNorm3d(out_filters, momentum=0.8))

    if gaussian_kernel is not None:
        gaussian_filter = nn.Parameter(torch.randn(1, 1, gaussian_kernel, gaussian_kernel, gaussian_kernel) * 1 + 1)
        block.append(gaussian_filter)

    return block

class GridWorld:
    def __init__(self, grid):
        self.grid = grid
        self.rows = len(grid)
