class Memory:
    def __init__(self):
        self.memory = {}

    def add_state(self, state, value):
        self.memory[state] = value

    def get_state(self, state):
        return self.memory.get(state, None)

def calculate_empowerment(gridworld, horizon, use_segments=False, use_memory=False):
    def get_neighbors(cell):
        row, col = cell
        neighbors = []
        if row > 0: neighbors.append((row - 1, col))
        if row < gridworld.rows - 1: neighbors.append((row + 1, col))
        if col > 0: neighbors.append((row, col - 1))
        if col < gridworld.cols - 1: neighbors.append((row, col + 1))
        return neighbors

    def dfs(cell, depth, visited):
        if depth == 0:
            return 1
        visited.add(cell)
        count = 1
        for neighbor in get_neighbors(cell):
            if neighbor not in visited:
                count += dfs(neighbor, depth - 1, visited.copy())
        return count

    def evaluate_cell(cell):
        if use_memory:
            state = (cell, horizon)
            value = memory.get_state(state)
            if value is not None:
                return value
        visited = set()
        empowerment = dfs(cell, horizon, visited)
        if use_memory:
            memory.add_state(state, empowerment)
        return empowerment

    def evaluate_segment(segment):
        total_empowerment = 0
        for cell in segment:
            total_empowerment += evaluate_cell(cell)
        return total_empowerment

    memory = Memory() if use_memory else None
    total_empowerment = 0

    if use_segments:
        segments = get_segments(gridworld)
        for segment in segments:
            total_empowerment += evaluate_segment(segment)
    else:
        for row in range(gridworld.rows):
            for col in range(gridworld.cols):
                total_empowerment += evaluate_cell((row, col))

    return total_empowerment

def get_segments(gridworld):
    segments = []
    visited = set()
    for row in range(gridworld.rows):
        for col in range(gridworld.cols):
            cell = (row, col)
            if cell not in visited:
                segment = set()
                stack = [cell]
                while stack:
                    current = stack.pop()
                    if current not in visited:
                        visited.add(current)
                        segment.add(current)
                        for neighbor in get_neighbors(current):
                            if neighbor not in visited:
                                stack.append(neighbor)
                segments.append(segment)
    return segments

