class Table:
    def __init__(self, schema: str, table_name: str):
        self.schema = schema
        self.table_name = table_name

    def __eq__(self, other: 'Table') -> bool:
        if isinstance(other, Table):
            return self.schema == other.schema and self.table_name == other.table_name
        return False

    def __hash__(self) -> int:
        return hash(f"{self.schema}-{self.table_name}")

def compare_tables(tables: List[Table]) -> Dict[Table, List[Table]]:
    table_dict = {}
    for table in tables:
        found = False
        for key in table_dict:
            if table == key:
                table_dict[key].append(table)
                found = True
                break
        if not found:
            table_dict[table] = [table]
