        if unique_id in self.pipelines:
            raise ValueError("Pipeline with this ID already exists.")
        pipeline = Pipeline(unique_id)
        self.pipelines[unique_id] = pipeline
        return pipeline

    def create_coupling(self, pipeline1_id, pipeline2_id):
        if pipeline1_id not in self.pipelines or pipeline2_id not in self.pipelines:
            raise ValueError("One or both pipelines do not exist.")
        coupling = PipelineCoupling(self.pipelines[pipeline1_id], self.pipelines[pipeline2_id])
        self.couplings.append(coupling)
        return coupling

    def get_pipeline_couplings(self, pipeline_id):
        return [coupling for coupling in self.couplings if pipeline_id in (coupling.pipeline1.unique_id, coupling.pipeline2.unique_id)]

