def process_nested_data(args):
    first_element = args[0]

    if isinstance(first_element, list) and all(isinstance(sublist, list) and all(isinstance(item, dict) for item in sublist) for sublist in first_element):
        return [dict(item for sublist in first_element for item in sublist)]

    elif isinstance(first_element, list) and all(isinstance(sublist, list) and all(isinstance(item, np.ndarray) for item in sublist) for sublist in first_element):
        return [np.concatenate(sublist) for sublist in first_element]

    elif isinstance(first_element, list) and all(isinstance(sublist, list) and all(isinstance(item, list) and all(isinstance(arr, np.ndarray) for arr in item) for item in sublist) for sublist in first_element):
        return [[np.concatenate(item) for item in sublist] for sublist in first_element]

