import math

def dot_product(vector1, vector2):
    result = 0
    for key in vector1:
        if key in vector2:
            result += vector1[key] * vector2[key]
    return result

def euclidean_norm(vector):
    return math.sqrt(sum(value ** 2 for value in vector.values()))

def sparse_cosine_similarity(vector1, vector2):
    if not vector1 or not vector2:
        return 0.0

    dot_prod = dot_product(vector1, vector2)
    norm1 = euclidean_norm(vector1)
    norm2 = euclidean_norm(vector2)

    if norm1 == 0 or norm2 == 0:
        return 0.0

    similarity = dot_prod / (norm1 * norm2)
    return round(similarity, 2)

import heapq

class Solution:
    def kSmallestPairs(self, nums1, nums2, k):
        if not nums1 or not nums2:
            return []

        heap = []
        for i in range(min(k, len(nums1))):
            for j in range(min(k, len(nums2))):
                pair_sum = nums1[i] + nums2[j]
                heapq.heappush(heap, (pair_sum, (nums1[i], nums2[j])))

        result = []
        for _ in range(k):
            if heap:
                _, pair = heapq.heappop(heap)
                result.append(pair)
            else:
                break

        return result

