def parse_licenses(licenses):
    license_info = {}
    for license in licenses:
        year_match = re.search(r'Copyright (\d{4})', license)
        name_match = re.search(r'Copyright \d{4} (.+?)\n', license)
        type_match = re.search(r'Licensed under the (.+)', license)

        if year_match and name_match and type_match:
            year = int(year_match.group(1))
