def max_min_diff(arr: List[int]) -> int:
    if len(arr) < 2:
        return 0

    min_val = arr[0]
    max_diff = 0

    for num in arr[1:]:
        if num > min_val:
            max_diff = max(max_diff, num - min_val)
        else:
            min_val = num

    return max_diff

