def process_fasta_files(fasta_files):
    def parse_fasta(file):
        with open(file, 'r') as f:
            lines = f.readlines()

        sequences = []
        current_seq = []
        current_id = None

        for line in lines:
            line = line.strip()
            if line.startswith('>'):
                if current_seq:
                    sequences.append((current_id, ''.join(current_seq)))
                    current_seq = []
                current_id = line[1:]
            else:
                current_seq.append(line.upper())

        if current_seq:
            sequences.append((current_id, ''.join(current_seq)))

        return sequences

    results = []

    for fasta_file in fasta_files:
        sequences = parse_fasta(fasta_file)
        for seq_id, seq in sequences:
            total_length = len(seq)
            seq_list = list(seq)
            results.append((seq_id, total_length, seq_list))

    return results

