def get_namespaces(xml_tags):
    namespaces = set()
    for tag in xml_tags:
        start = tag.find('<') + 1
        end = tag.find(':') if tag.find(':') != -1 else tag.find(' ')
        if end == -1:
            end = len(tag)
        namespace = tag[start:end]
        if namespace:
            namespaces.add(namespace)
    return list(namespaces) if namespaces else ["No namespace"]

