def removeOuterParentheses(s: str) -> str:
    result = []
    balance = 0
    start = 0

    for i, char in enumerate(s):
        if char == '(':
            balance += 1
        elif char == ')':
            balance -= 1

        if balance == 0:
            result.append(s[start + 1:i])
            start = i + 1

    return ''.join(result)

