import random

def fitness_function(agent_params):
    # Example fitness function, replace with actual fitness calculation
    return sum(agent_params.values())

def initialize_population(no_of_parents, agent_parameter_choices):
    population = []
    for _ in range(no_of_parents):
        agent = {param: random.choice(choices) for param, choices in agent_parameter_choices.items()}
        population.append(agent)
    return population

def select_parents(population, no_of_parents):
    # Tournament selection
    selected = []
    for _ in range(no_of_parents):
        candidates = random.sample(population, 2)
        winner = max(candidates, key=fitness_function)
        selected.append(winner)
    return selected

def crossover(parent1, parent2):
    # Single point crossover
    child = {}
    crossover_point = random.choice(list(parent1.keys()))
    for param in parent1:
        if param <= crossover_point:
            child[param] = parent1[param]
        else:
            child[param] = parent2[param]
    return child

def mutate(agent, agent_parameter_choices, mutation_rate=0.1):
    for param in agent:
        if random.random() < mutation_rate:
            agent[param] = random.choice(agent_parameter_choices[param])
    return agent

def evolutionary_algorithm(generations, no_of_parents, agent_parameter_choices):
    population = initialize_population(no_of_parents, agent_parameter_choices)

    for _ in range(generations):
        parents = select_parents(population, no_of_parents)
        new_population = []

        for i in range(0, no_of_parents, 2):
            parent1 = parents[i]
            parent2 = parents[i + 1] if i + 1 < no_of_parents else parents[0]
            child1 = crossover(parent1, parent2)
            child2 = crossover(parent2, parent1)
            child1 = mutate(child1, agent_parameter_choices)
            child2 = mutate(child2, agent_parameter_choices)
            new_population.extend([child1, child2])

        population = new_population

    best_agent = max(population, key=fitness_function)
    return best_agent

