from functools import partial

def solution_layered(_tristate_armed, _layered_solution):
    """
    Like set_layered_solution() as a context-manager, resetting back to the old value.
    """
    def context_manager():
        old_value = _tristate_armed()
        _tristate_armed(_layered_solution)
        try:
            yield 'reset'
        finally:
            _tristate_armed(old_value)

    return partial(context_manager)

