import random

class DLA:
    @staticmethod
    def main_single(grid_size, num_particles, stickiness):
        grid = [[0] * grid_size for _ in range(grid_size)]
        center = grid_size // 2
        grid[center][center] = 1  # Seed particle at the center

        def is_valid(x, y):
            return 0 <= x < grid_size and 0 <= y < grid_size

        def move_particle(x, y):
            directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
            dx, dy = random.choice(directions)
            new_x, new_y = x + dx, y + dy
            return new_x, new_y

        def check_stick(x, y):
            neighbors = [(x+1, y), (x-1, y), (x, y+1), (x, y-1),
                         (x+1, y+1), (x+1, y-1), (x-1, y+1), (x-1, y-1)]
            for nx, ny in neighbors:
                if is_valid(nx, ny) and grid[nx][ny] == 1:
                    if random.random() < stickiness:
                        return True
            return False

        for _ in range(num_particles):
            x, y = random.randint(0, grid_size-1), random.randint(0, grid_size-1)
            while True:
                if grid[x][y] == 1:
                    continue
                if check_stick(x, y):
                    grid[x][y] = 1
                    break
                x, y = move_particle(x, y)

        for row in grid:
            print(' '.join(['#' if cell else '.' for cell in row]))

