from math import *

def evaluate_expression(expression, vars={}):
    def eval_exp(match):
        exp = match.group(0)
        try:
            return str(eval(exp, vars))
        except KeyError as e:
            raise KeyError(f"Variable not found: {e}")

    pattern = r'\b[a-zA-Z_][a-zA-Z0-9_]*\b'
    expression = re.sub(pattern, eval_exp, expression)
    return eval(expression, vars)

