class ConversionHandler:
    def __init__(self, conversions: List[Tuple[int, str, Any]]):
        self._conversions = conversions
        self._selected_conversion = None

    def _GetConversion(self, number: int) -> Tuple[int, str, Any]:
        for conversion in self._conversions:
            if conversion[0] == number:
                return conversion
        return None

    def _MoveDown(self, only_selected: bool = True):
        if only_selected:
            selected_conversion = self._GetConversion(self._selected_conversion[0])
            if selected_conversion:
                number, conversion_type, data = selected_conversion
                next_conversion = self._GetConversion(number + 1)
                if next_conversion:
                    self._selected_conversion = next_conversion

    def NextConversion(self) -> Tuple[int, str, Any]:
        if self._selected_conversion:
            next_number = self._selected_conversion[0] + 1
            next_conversion = self._GetConversion(next_number)
            return next_conversion
        return None

