def convert_time(input_data: dict) -> List[int]:
    tm = [0, 0, 0, 0, 0, 0]

    if "hour" in input_data:
        tm[3] = input_data["hour"]
    elif "hour12" in input_data and "ampm12" in input_data:
        if input_data["ampm12"].lower() == "am":
            tm[3] = input_data["hour12"] % 12
        elif input_data["ampm12"].lower() == "pm":
            tm[3] = (input_data["hour12"] % 12) + 12

    tm[4] = input_data.get("minute", 0)
    tm[5] = input_data.get("second", 0)

