import random

class Environment:
    def __init__(self, num_agents, action_space):
        self.num_agents = num_agents
        self.action_space = action_space
        self.agents = [Agent(i, action_space) for i in range(num_agents)]
        self.goal_achieved = False

    def step(self):
        for agent in self.agents:
            action = agent.choose_action()
            observation, reward, done = self.perform_action(agent, action)
            agent.update_state(observation, reward, done)
            if done:
                self.goal_achieved = True

    def perform_action(self, agent, action):
        # Simulate environment feedback
        observation = random.choice(self.action_space)
        reward = random.randint(0, 10)
        done = reward == 10  # Goal achieved if reward is 10
        return observation, reward, done

class Agent:
    def __init__(self, id, action_space):
        self.id = id
        self.action_space = action_space
        self.observation = None
        self.reward = 0
        self.done = False

    def choose_action(self):
        return random.choice(self.action_space)

    def update_state(self, observation, reward, done):
        self.observation = observation
        self.reward = reward
        self.done = done

# Example usage
