from ..ast import AVMLabel, BlockStatement
from ..compiler import compile_block

def compile_block(block: BlockStatement) -> str:
    compiled_statements = []
    for statement in block.statements:
        if isinstance(statement, AVMLabel):
            compiled_statements.append(f"Label: {statement.name}")
        elif isinstance(statement, BlockStatement):
            compiled_statements.append(compile_block(statement))
    return "{\n" + "\n".join(compiled_statements) + "\n}"

