from typing import List

def calculate_total_ways(score: int, scoring_event: int, number_of_ways: int) -> List[int]:
    dictionary_of_scores = {0: 1}
    list_to_return = []
    current_score = 0

    while current_score <= score:
        new_score = current_score + scoring_event
        if new_score != 0:
            if new_score in dictionary_of_scores:
                dictionary_of_scores[new_score] += number_of_ways * dictionary_of_scores[current_score]
            else:
                dictionary_of_scores[new_score] = number_of_ways * dictionary_of_scores[current_score]
        current_score += scoring_event
        list_to_return.append(dictionary_of_scores[current_score - scoring_event])

    return list_to_return

