class IndexedTransformer:
    def __init__(self, transformer, padding, step):
        self.transformer = transformer
        self.padding = padding
        self.step = step

    def index_data(self):
        transformed_data = self.transformer.transform()
        indexed_data = [transformed_data[i] for i in range(0, len(transformed_data), self.step)]
        return indexed_data

    def apply_padding(self):
        indexed_data = self.index_data()
        padded_data = [0] * self.padding + indexed_data + [0] * self.padding
        return padded_data

