def get_web_link_labels(menu):
    unique_labels = set()
    for menu_item in menu.get("menu", []):
        for item in menu_item.get("menuItems", []):
            if item.get("action") == "webLink":
                unique_labels.add(item.get("label"))
    return list(unique_labels)

