                    if hasattr(module, 'split_rate') and module.split_rate < 1.0:
                        if evolve_mode == "rand":
                            module.weight.data *= module.mask
                        elif evolve_mode == "grow":
                            module.weight.data += (1 - module.mask) * torch.randn_like(module.weight) * module.split_rate
                        elif evolve_mode == "shrink":
                            module.weight.data *= (1 - module.split_rate) + module.split_rate * module.mask

