class RecursionAnalyzer:
    def __init__(self):
        self._max_recursion_depth = 0
        self._num_guesses = 0

    @property
    def num_guesses(self):
        return self._num_guesses

    @num_guesses.setter
    def num_guesses(self, value):
        self._num_guesses = value

    def on_recursion(self, depth):
        if depth > self._max_recursion_depth:
            self._max_recursion_depth = depth

    def get_max_recursion_depth(self):
        return self._max_recursion_depth

def factorial(n, analyzer, depth=0):
    analyzer.on_recursion(depth)
    if n == 0:
        return 1
    else:
        return n * factorial(n - 1, analyzer, depth + 1)

