def solve(x):
    if x == 0:
        return 0
    sign = -1 if x < 0 else 1
    x = abs(x)
    d = 0
    while x:
        d = d * 10 + x % 10
        x //= 10
        if d < -2**31 or d > 2**31 - 1:
            return 0
    return sign * d

