class APIRouter:
    def __init__(self):
        self.routes = {}

    def include_router(self, router, tags=[], prefix="/"):
        self.routes[prefix] = (router, tags)

    def route(self, path):
        def decorator(func):
            def wrapper(*args, **kwargs):
                return func(*args, **kwargs)
            return wrapper
        return decorator

    def handle_request(self, path, *args, **kwargs):
        if path in self.routes:
            router, _ = self.routes[path]
            return router.process_request(*args, **kwargs)
