import numpy as np

class BinomialCrossEntropy:
    def __init__(self, epsilon=1e-7):
        self.epsilon = epsilon

    def get(self, y, t):
        y = np.clip(y, self.epsilon, 1 - self.epsilon)  # Clip to prevent log(0) and log(1)
        error = -t * np.log(y) - (1 - t) * np.log(1 - y)
        loss = np.mean(error)
        return loss

