class FileBuffer:
    def __init__(self, socket: socket.socket):
        self.socket = socket

    def read(self, n: int) -> bytes:
        data = bytearray()
        while len(data) < n:
            chunk = self.socket.recv(n - len(data))
            if not chunk:
                raise EOFError("Not enough data available to read the specified number of bytes")
            data.extend(chunk)
        return bytes(data)

    def dispose(self) -> None:
        try:
            self.socket.close()
        except Exception as e:
            core.log_exception(e)

