import hashlib
import json

class Block:
    def __init__(self, index, data, previous_hash):
        self.index = index
        self.data = data
        self.previous_hash = previous_hash
        self.hash = self.calculate_hash()

    def calculate_hash(self):
        block_string = json.dumps({"index": self.index, "data": self.data, "previous_hash": self.previous_hash}, sort_keys=True).encode()
        return hashlib.sha256(block_string).hexdigest()

def load_blockchain(filename):
    blockchain = []
    with open(filename, 'r') as file:
        for line in file:
            block_data = json.loads(line)
            block = Block(block_data['index'], block_data['data'], block_data['previous_hash'])
            blockchain.append(block)
    return blockchain

def verify_blockchain(chain, official_public_key, expected_hash):
    for block in chain:
        if block.hash != expected_hash:
