import heapq

def beam_search_with_pruning(input_text, probabilities, beam_width, cutoff_top_n):
    def get_top_n_chars(probabilities, n):
        return heapq.nlargest(n, probabilities, key=probabilities.get)

    def expand_sequence(sequence, top_n_chars):
        expanded = []
        for char in top_n_chars:
            expanded.append(sequence + char)
        return expanded

    top_n_chars = get_top_n_chars(probabilities, cutoff_top_n)
    beam = [(input_text, 1.0)]  # (sequence, probability)

    for _ in range(len(input_text), len(input_text) + beam_width):
        candidates = []
        for sequence, prob in beam:
            expanded_sequences = expand_sequence(sequence, top_n_chars)
            for seq in expanded_sequences:
                char = seq[-1]
                new_prob = prob * probabilities[char]
                candidates.append((seq, new_prob))

        candidates.sort(key=lambda x: x[1], reverse=True)
        beam = candidates[:beam_width]

    return [seq for seq, _ in beam]

