import os
from typing import List

def unasync_path(async_folder: str, sync_folder: str, create_missed_paths: bool = False) -> List[str]:
    if not os.path.exists(async_folder):
        raise RuntimeError(f"The folder {async_folder} does not exist.")

    if not os.path.exists(sync_folder):
        if create_missed_paths:
            os.makedirs(sync_folder)
        else:
            raise RuntimeError(f"The folder {sync_folder} does not exist.")

    sync_paths = []
    for root, _, files in os.walk(async_folder):
        for file in files:
            if file.endswith('_async.txt'):
                async_path = os.path.join(root, file)
                rel_path = os.path.relpath(async_path, async_folder)
                sync_file = rel_path.replace('_async.txt', '_sync.txt')
                sync_path = os.path.join(sync_folder, sync_file)

                sync_dir = os.path.dirname(sync_path)
                if not os.path.exists(sync_dir):
                    if create_missed_paths:
                        os.makedirs(sync_dir)
                    else:
                        raise RuntimeError(f"The path {sync_dir} does not exist.")

                sync_paths.append(sync_path)

    return sync_paths

