def balanceParentheses(s: str) -> bool:
    left_count = 0
    right_count = 0
    star_count = 0

    # Traverse the string from right to left
    for char in s[::-1]:
        if char == ')':
            right_count += 1
        elif char == '*':
            star_count += 1
        elif char == '(':
            if right_count > 0:
                right_count -= 1
            elif star_count > 0:
                star_count -= 1
            else:
                return False

    # Reset counts for the second pass from left to right
    left_count = 0
    star_count = 0

    # Traverse the string from left to right
    for char in s:
        if char == '(':
            left_count += 1
        elif char == '*':
            star_count += 1
        elif char == ')':
            if left_count > 0:
                left_count -= 1
            elif star_count > 0:
                star_count -= 1
            else:
                return False

    return True

