class Queue:
    def __init__(self, max_size=None):
        self.queue = []
        self.max_size = max_size

    def enqueue(self, item):
        if not self.is_full():
            self.queue.append(item)
        else:
            raise IndexError("Queue is full")

    def dequeue(self):
        if not self.is_empty():
            return self.queue.pop(0)
        else:
            return None

    def is_empty(self):
        return len(self.queue) == 0

    def is_full(self):
        if self.max_size is not None:
            return len(self.queue) >= self.max_size
        return False

class PositiveNegativeNumber:
    def __init__(self, pos=None, allow_zero=False):
        self._pos = None
        self.allow_zero = allow_zero
        self.pos = pos  # This will trigger the setter

    @property
    def pos(self):
        return self._pos

    @pos.setter
    def pos(self, value):
        if value is not None:
            if value > 0:
                if not self.allow_zero and value == 0:
                    raise ValueError("Zero is not allowed as a positive number.")
                elif value <= 0:
                    raise ValueError("Positive number must be greater than the specified value.")
            elif value < 0:
                if value >= 0:
                    raise ValueError("Negative number must be less than the specified value.")
            else:
                raise ValueError("The number must be either positive or negative.")
        self._pos = value

