import numpy as np

def symmetric_elliot(x):
    return x / (1 + np.abs(x))

def softplus(x):
    return np.log(1 + np.exp(x))

def npdl_act(input):
    output = np.zeros_like(input)
    for i in range(input.shape[0]):
        for j in range(input.shape[1]):
            if (i + j) % 2 == 0:
                output[i, j] = symmetric_elliot(input[i, j])
            else:
                output[i, j] = softplus(input[i, j])
    return output

