def count_columns_and_lines(filename: str) -> tuple:
    try:
        with open(filename, 'r') as file:
            lines = file.readlines()
            if not lines:
                return (0, 0)
            first_line = lines[0].strip()
            columns = len(first_line.split(','))
            rows = len(lines)
            return (columns, rows)
    except FileNotFoundError:
