import ast

def count_unique_dependencies(code_snippet):
    # Parse the code snippet into an abstract syntax tree
    tree = ast.parse(code_snippet)

    # Initialize sets to store unique dependencies
    tests_require_set = set()
    extras_require_set = set()

    # Traverse the AST to find the lists and dictionaries
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == 'tests_require':
                    if isinstance(node.value, ast.List):
                        for element in node.value.elts:
                            if isinstance(element, ast.Constant):
                                tests_require_set.add(element.value)
                elif isinstance(target, ast.Name) and target.id == 'extras_require':
                    if isinstance(node.value, ast.Dict):
                        for key, value in zip(node.value.keys, node.value.values):
                            if isinstance(value, ast.List):
                                for element in value.elts:
                                    if isinstance(element, ast.Constant):
                                        extras_require_set.add(element.value)

    # Calculate the total number of unique dependencies
    total_unique_dependencies = len(tests_require_set) + len(extras_require_set)

    return total_unique_dependencies

