class Graph:
    def __init__(self):
        self.nodes = {}

    def add_node(self, uid):
        if uid not in self.nodes:
            self.nodes[uid] = set()

    def remove_node(self, uid):
        assert uid in self.nodes, f"node {uid} not in graph"
        for connected_uid in self.nodes[uid]:
            self.nodes[connected_uid].remove(uid)
        del self.nodes[uid]

    def add_connection(self, uid1, uid2):
        assert uid1 in self.nodes, f"node {uid1} not in graph"
        assert uid2 in self.nodes, f"node {uid2} not in graph"
        self.nodes[uid1].add(uid2)
        self.nodes[uid2].add(uid1)

    def remove_connection(self, uid1, uid2):
        assert uid1 in self.nodes, f"node {uid1} not in graph"
        assert uid2 in self.nodes, f"node {uid2} not in graph"
        assert uid2 in self.nodes[uid1], f"nodes {uid1} and {uid2} not connected"
        self.nodes[uid1].remove(uid2)
        self.nodes[uid2].remove(uid1)

