import math

def transit(grid, n, indices, values):
    for i, idx in enumerate(indices):
        x, y = idx
        if 0 <= x < n and 0 <= y < n:
            grid[x][y] = values[i]

def inverse(grid, m, k):
    for i in range(1, min(m, k) + 1):
        grid[i-1][i-1] = 1 / grid[i-1][i-1] if grid[i-1][i-1] != 0 else 0

def magnitude(grid, p, indices, factor):
    for idx in indices:
        x, y = idx
        if 0 <= x < p and 0 <= y < p:
            grid[x][y] *= factor

def sin(grid, q, x, y, z):
    grid[q][q] = math.sin(x * y * z)

