def roman_to_int(s: str) -> int:
    roman_to_int_map = {
        'I': 1,
        'V': 5,
        'X': 10,
        'L': 50,
        'C': 100,
        'D': 500,
        'M': 1000
    }

    total = 0
    prev_value = 0

    for char in reversed(s):
        value = roman_to_int_map[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value

    return total

import socket
import select

# Server code
class ChatServer:
    def __init__(self, host='127.0.0.1', port=6000):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setblocking(False)
        self.server_socket.bind((host, port))
        self.server_socket.listen(5)
        self.client_sockets = []
        self.inputs = [self.server_socket]
        print("Server started, waiting for clients...")

    def run(self):
        while True:
            readable, writable, exceptional = select.select(self.inputs, [], self.inputs)
            for s in readable:
                if s is self.server_socket:
                    client_socket, client_address = s.accept()
                    client_socket.setblocking(False)
                    self.inputs.append(client_socket)
                    self.client_sockets.append(client_socket)
                    print(f"Client {client_address} connected")
                else:
                    try:
                        data = s.recv(1024)
                        if data:
                            self.broadcast(data, s)
                        else:
                            self.remove_client(s)
                    except ConnectionResetError:
                        self.remove_client(s)

            for s in exceptional:
                self.remove_client(s)

    def broadcast(self, message, source_socket):
        for client_socket in self.client_sockets:
            if client_socket != source_socket:
                try:
                    client_socket.send(message)
                except:
                    self.remove_client(client_socket)

    def remove_client(self, client_socket):
        if client_socket in self.inputs:
            self.inputs.remove(client_socket)
        if client_socket in self.client_sockets:
            self.client_sockets.remove(client_socket)
        client_socket.close()
        print("Client disconnected")

# Client code
class ChatClient:
    def __init__(self, host='127.0.0.1', port=6000):
        self.client_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.client_socket.connect((host, port))
        print("Connected to server")

    def run(self):
        import threading
        receive_thread = threading.Thread(target=self.receive_messages)
        receive_thread.start()

        while True:
            message = input()
            if message.lower() == 'exit':
                break
            self.client_socket.send(message.encode('utf-8'))

        self.client_socket.close()

    def receive_messages(self):
        while True:
            try:
                message = self.client_socket.recv(1024)
                if message:
                    print(message.decode('utf-8'))
                else:
                    break
            except ConnectionResetError:
                break
        self.client_socket.close()

