import math

def transform_dict(data):
    transformed = {}
    for key, value in data.items():
        if isinstance(value, str):
            transformed[value[::-1]] = key[::-1]
        elif isinstance(value, int):
            transformed[value] = math.factorial(value)
        elif isinstance(value, list):
            transformed[key] = [len(item) for item in value]
        elif value is None:
            transformed[key] = ""

    return {v: k for k, v in transformed.items()}

