class MemoryRegion:
    READABLE = 1
    WRITEABLE = 2
    COPY_ON_WRITE = 4

    def __init__(self, protect):
        self.protect = protect

    def is_readable(self):
        return (self.protect & self.READABLE) != 0

    def is_writeable(self):
        return (self.protect & self.WRITEABLE) != 0

    def is_copy_on_write(self):
        return (self.protect & self.COPY_ON_WRITE) != 0

    def has_content(self):
        return self.protect != 0

    def missing_protection(self):
        missing = []
        if not self.is_readable():
            missing.append("READABLE")
        if not self.is_writeable():
            missing.append("WRITEABLE")
        if not self.is_copy_on_write():
            missing.append("COPY_ON_WRITE")
        return missing

def custom_sort(arr):
    for i in range(len(arr)):
        for j in range(0, len(arr) - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

def apply_migrations(operations):
    schema = {}

    for operation in operations:
        if isinstance(operation, AlterField):
            model_name = operation.model_name
            field_name = operation.name
            field_attrs = {
                'name': field_name,
                'type': operation.field.__class__.__name__,
                'blank': operation.field.blank,
                'max_length': operation.field.max_length,
                'null': operation.field.null
            }

            if model_name not in schema:
                schema[model_name] = []

            schema[model_name].append(field_attrs)

    return schema

