import json
import sys
import argparse

def validate_json_data(data, options, workdir):
    if not isinstance(data, dict):
        raise ValueError("Invalid JSON format")

    if options.site and data.get('site') != options.site:
        raise ValueError("Site mismatch")

    if options.local_disk and not data.get('local_disk'):
        raise ValueError("Local disk information missing")

    if workdir and not data.get('workdir') == workdir:
        raise ValueError("Workdir mismatch")

    return True

def build_valid_netstat_keys(data):
    netstat_keys = set()
    if 'network_stats' in data:
        for key in data['network_stats']:
            if isinstance(data['network_stats'][key], dict):
                netstat_keys.add(key)
    return sorted(netstat_keys)

def main():
    parser = argparse.ArgumentParser(description="Process and validate host statistics JSON data")
    parser.add_argument('--site', type=str, help='Site name to validate')
    parser.add_argument('--local_disk', action='store_true', help='Validate local disk information')
    parser.add_argument('--workdir', type=str, help='Work directory to validate')
    parser.add_argument('--list_netstat', action='store_true', help='List network statistic keys')
    parser.add_argument('--all_netstat', action='store_true', help='Include all network statistic keys')
    args = parser.parse_args()

    try:
        with open('host_stats.json', 'r') as file:
            data = json.load(file)
    except FileNotFoundError:
        print("Error: host_stats.json not found")
        sys.exit(1)
    except json.JSONDecodeError:
        print("Error: Invalid JSON format in host_stats.json")
        sys.exit(1)

    try:
        validate_json_data(data, args, args.workdir)
    except ValueError as e:
        print(f"Validation Error: {e}")
