from typing import List

def merge_chunks(chunk_seq: List[int]) -> List[int]:
    seen = set()
    merged_list = []
    for chunk in chunk_seq:
        if chunk not in seen:
            seen.add(chunk)
            merged_list.append(chunk)
    return sorted(merged_list)

class SequenceGenerator:
    def newmeth(self, start):
        sequence = [start]
        while start != 1:
            if start % 2 == 0:
                start = start // 2
            else:
                start = 3 * start + 1
            sequence.append(start)
        return sequence

