            for class_idx in range(N_class):
                if class_idx == 0:
                    data = data10
                elif class_idx == 1:
                    data = data11
                elif class_idx == 2:
                    data = data12
                elif class_idx == 3:
                    data = data13

                for pos in N_pos:
                    fft_data = np.abs(np.fft.fft(data[pos, chan, trial]))
                    start_idx = (chan_idx * N_class * n_harmonicas) + (class_idx * n_harmonicas)
                    F_dez[trial, start_idx:start_idx + N_features] = fft_data[:N_features]

    return F_dez

