import numpy as np

def reconstruct_image(result, img_shape):
    height, width, channels = img_shape
    block_size = 8
    reconstructed_image = np.zeros(img_shape, dtype=result.dtype)

    for y in range(0, height, block_size):
        for x in range(0, width, block_size):
            for c in range(channels):
                max_value = result[y // block_size, x // block_size, c]
                reconstructed_image[y:y+block_size, x:x+block_size, c] = max_value

    return reconstructed_image

