import time

class RetryInterrupt(BaseException):
    countdown = 5  # Default countdown period in seconds
    queue = []

    def __str__(self):
        return f"RetryInterrupt: Retrying tasks in {self.countdown} seconds"

    @classmethod
    def add_task(cls, task):
        cls.queue.append(task)

    @classmethod
    def retry_tasks(cls):
        if cls.queue:
            print(f"Starting retry process in {cls.countdown} seconds...")
            time.sleep(cls.countdown)
            print("Retrying tasks:", cls.queue)
            cls.queue.clear()
        else:
            print("No tasks to retry.")

