def count_art_elements(figures):
    def dfs(x, y):
        if x < 0 or x >= len(figure) or y < 0 or y >= len(figure[0]) or figure[x][y] != '*':
            return
        figure[x][y] = '.'
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        for dx, dy in directions:
            dfs(x + dx, y + dy)

    results = []
    for figure in figures:
        rows = len(figure)
        cols = len(figure[0])
        figure = [list(row) for row in figure]
        count = 0
        for i in range(rows):
            for j in range(cols):
                if figure[i][j] == '*':
                    dfs(i, j)
                    count += 1
        results.append(count)
    return results

