from collections import Counter
import math

def calculate_bleu_score(hypotheses, list_of_references):
    def count_ngrams(sentence, n):
        return Counter(tuple(sentence[i:i+n]) for i in range(len(sentence) - n + 1))

    def modified_precision(hypothesis, references, n):
        hyp_ngram_counts = count_ngrams(hypothesis, n)
        max_ref_ngram_counts = Counter()
        for reference in references:
            ref_ngram_counts = count_ngrams(reference, n)
            for ngram in hyp_ngram_counts:
                max_ref_ngram_counts[ngram] = max(max_ref_ngram_counts[ngram], ref_ngram_counts[ngram])
        clipped_counts = {ngram: min(count, max_ref_ngram_counts[ngram]) for ngram, count in hyp_ngram_counts.items()}
        return sum(clipped_counts.values()) / sum(hyp_ngram_counts.values()) if hyp_ngram_counts else 0

    def brevity_penalty(hypothesis, references):
        hyp_len = len(hypothesis)
        ref_lens = [len(reference) for reference in references]
        closest_ref_len = min(ref_lens, key=lambda x: (abs(x - hyp_len), x))
        if hyp_len > closest_ref_len:
            return 1
        else:
            return math.exp(1 - closest_ref_len / hyp_len) if hyp_len > 0 else 0

    bleu_scores = []
    for hyp, refs in zip(hypotheses, list_of_references):
        precisions = [modified_precision(hyp, refs, n) for n in range(1, 5)]
        bp = brevity_penalty(hyp, refs)
        if all(p > 0 for p in precisions):
            bleu = bp * math.exp(sum(math.log(p) for p in precisions) / 4)
        else:
            bleu = 0
        bleu_scores.append(bleu)
    return bleu_scores

