def extract_powered_property(messages: List[Tuple[str, str, str, str, Tuple[str, Union[str, bool]]]]) -> Dict[str, List[Union[str, bool]]]:
    powered_dict = {}
    for _, device_path, _, signal_type, (property_name, property_value) in messages:
        if signal_type == 'PropertyChanged' and property_name == 'Powered':
            if device_path not in powered_dict:
                powered_dict[device_path] = []
