def determine_final_official_and_dev_version(tag_list):
    if not tag_list:
        return "0.0.0", "0.0.0"

    def parse_version(tag):
        try:
            return tuple(map(int, tag.split('.')))
        except ValueError:
            return (0, 0, 0)

    parsed_tags = {parse_version(tag): tag for tag in tag_list}
    max_official_version = max(parsed_tags)
