def decode(core: bytes) -> str:
    result = []
    i = 0
    while i < len(core):
        if core[i].isalpha():
            letter = core[i]
            i += 1
            if i < len(core) and core[i].isdigit():
                shift = int(core[i])
                if shift == 0:
                    continue
                new_char = chr(((ord(letter) - ord('a') + shift) % 26) + ord('a'))
                result.append(new_char)
                i += 1
            else:
                result.append(letter)
        else:
            i += 1
    return ''.join(result)

