        lines = file.readlines()
        loc_count = 0
        for line in lines:
            stripped_line = line.strip()
            if stripped_line and not stripped_line.startswith('#'):
                loc_count += 1
    return loc_count

import math

def is_perfect_square(num):
    root = math.isqrt(num)
    return num == root * root

def count_distinct_pairs(scores):
    count = 0
    n = len(scores)
    for i in range(n):
        for j in range(i + 1, n):
            if is_perfect_square(abs(scores[i] - scores[j])):
                count += 1
    return count

