import numpy as np

def closest_to_centroid(clusters, centroids, nb_closest=20):
    closest_indices = []
    for centroid in centroids:
        distances = []
        for cluster in clusters:
            if len(cluster) > 0:
                dist = np.linalg.norm(np.array(cluster) - np.array(centroid), axis=1)
                distances.append(dist)
            else:
                distances.append(np.array([float('inf')]))
        distances = np.concatenate(distances)
        closest = np.argsort(distances)[:nb_closest]
        closest_indices.append(closest.tolist())
    return closest_indices

