from collections import defaultdict

def generate_ngrams(n, corpus):
    ngrams = defaultdict(list)
    for sentence in corpus:
        words = sentence.split()
        for i in range(len(words) - n + 1):
            gram = ' '.join(words[i:i+n])
            prefix = ' '.join(words[i:i+n-1])
            ngrams[prefix].append(gram)
    return ngrams

def find_specific_sequence(corpus, past_n_target, past_n_min, forward_n, min_ngrams_needed):
    # Generate n-grams from the corpus
    all_ngrams = generate_ngrams(past_n_target + forward_n, corpus)

    # Initial n-gram sequence
    generated = ['the']

    while len(generated) < min_ngrams_needed:
        last_ngram = ' '.join(generated[-past_n_target:])
        if last_ngram in all_ngrams:
            candidates = [ngram for ngram in all_ngrams[last_ngram] if len(ngram.split()) >= past_n_min]
            if candidates:
                generated.append(candidates[0].split()[-1])
            else:
                break
        else:
            break

    # Return the specific sequence of n-grams found
    return generated

import re

class Token:
    def __init__(self, type, value=None):
        self.type = type
        self.value = value

class Tokenizer:
    def __init__(self, rules):
        self.rules = rules
        self.patterns = self._build_patterns()

    def _build_patterns(self):
        patterns = {}
        for key, value in self.rules.items():
            tokens = key.split()
            patterns[key] = (tokens, value)
        return patterns

    def tokenize(self, input_string):
        tokens = []
        while input_string:
            match_found = False
            for key, (token_patterns, token_types) in self.patterns.items():
                for pattern in token_patterns:
                    if input_string.startswith(pattern):
                        tokens.append(Token(token_types.pop(0), pattern))
                        input_string = input_string[len(pattern):].lstrip()
                        match_found = True
                        break
                if match_found:
                    break
            if not match_found:
                raise ValueError(f"Unexpected character in input: {input_string}")
        return tokens

