import argparse
import random
import time

def parse_args():
    parser = argparse.ArgumentParser(description="Process Monitoring Script")
    parser.add_argument("--threshold", type=int, default=50, help="Resource usage threshold")
    parser.add_argument("--monitor", action="store_true", help="Enable continuous monitoring")
    return parser.parse_args()

def generate_processes(num_processes=10):
    processes = []
    for _ in range(num_processes):
        pid = random.randint(1000, 9999)
        resource_usage = random.randint(1, 100)
        processes.append((pid, resource_usage))
    return processes

def filter_processes(processes, threshold):
    return [process for process in processes if process[1] > threshold]

def report(offending_processes):
    if offending_processes:
        print("Offending Processes:")
        for pid, usage in offending_processes:
            print(f"PID: {pid}, Resource Usage: {usage}")
    else:
        print("No offending processes found.")

def main():
    args = parse_args()
    while True:
        processes = generate_processes()
        offending_processes = filter_processes(processes, args.threshold)
        report(offending_processes)
        if not args.monitor:
            break
        time.sleep(5)  # Sleep for 5 seconds before next iteration

if __name__ == "__main__":
    main()

