from scipy.optimize import approx_fprime

def jacobian(fun):
    def J(x):
        return approx_fprime(x, fun, epsilon=1e-6)
    return J

def main():
    def sample_fun(x):
        return np.array([x[0]**2 + x[1], x[0] * x[1]])

    J = jacobian(sample_fun)

    def wrapper(x):
        return sample_fun(x), J(x)

    x = np.array([1.0, 1.0])
    y, g = wrapper(x)
    print("Function output:", y)
    print("Jacobian matrix:", g)

