import re
from bs4 import BeautifulSoup

def clean_text(text):
    return re.sub(r'\[[0-9]+\]', '', text)

def extract_and_clean_text(html_file, div_id):
    with open(html_file, 'r', encoding='utf-8') as file:
        content = file.read()

    soup = BeautifulSoup(content, 'html.parser')
    div_tag = soup.find('div', id=div_id)

    if not div_tag:
        raise ValueError(f"No <div> tag with id '{div_id}' found in the HTML file.")

    cleaned_text = []
    for p_tag in div_tag.find_all('p'):
        text = p_tag.get_text(strip=True)
        cleaned_text.append(clean_text(text))

    return '\n'.join(cleaned_text)

def save_to_file(text, output_file):
    with open(output_file, 'w', encoding='utf-8') as file:
        file.write(text)

def main(html_file, div_id):
    cleaned_text = extract_and_clean_text(html_file, div_id)
    base_name = re.sub(r'[ /]', '-', html_file.rsplit('.', 1)[0])
    output_file = f"{base_name}.txt"
    save_to_file(cleaned_text, output_file)
    print(f"Cleaned text saved to {output_file}")

if __name__ == "__main__":
    import sys
    if len(sys.argv) != 3:
        print("Usage: python script.py <html_file> <div_id>")
    else:
        main(sys.argv[1], sys.argv[2])

def add_disc_sum_rew(trajectory, gamma=0.9):
    n = len(trajectory)
    disc_sum_rew = [0] * n
    for i in reversed(range(n)):
        state, action, reward, next_state = trajectory[i]
        if i == n - 1:
            disc_sum_rew[i] = reward
        else:
            disc_sum_rew[i] = reward + gamma * disc_sum_rew[i + 1]
        trajectory[i] = (state, action, reward, next_state, disc_sum_rew[i])

def build_train_set(trajectories):
    training_set = []
    for trajectory in trajectories:
        add_disc_sum_rew(trajectory)
        for state, action, reward, next_state, disc_sum_rew in trajectory:
            training_set.append((state, disc_sum_rew))
    return training_set

