def count_unanimous_answers(file_path):
    with open(file_path, 'r') as file:
        groups = file.read().split('\n\n')

    total_count = 0
    for group in groups:
        persons = group.split()
        if len(persons) == 1:
            total_count += len(persons[0])
        else:
            common_answers = set(persons[0])
            for person in persons[1:]:
                common_answers &= set(person)
            total_count += len(common_answers)

    return total_count

