import numpy as np

class GridWorld:
    def __init__(self, grid_size):
        self.grid_size = grid_size
        self.actions = [(0, 1), (0, -1), (1, 0), (-1, 0)]  # right, left, down, up
        self.reset()

    def reset(self):
        self.agent_pos = (np.random.randint(self.grid_size), np.random.randint(self.grid_size))
        self.goal_pos = (np.random.randint(self.grid_size), np.random.randint(self.grid_size))
        self.pit_pos = (np.random.randint(self.grid_size), np.random.randint(self.grid_size))
        while self.goal_pos == self.pit_pos or self.goal_pos == self.agent_pos or self.pit_pos == self.agent_pos:
            self.goal_pos = (np.random.randint(self.grid_size), np.random.randint(self.grid_size))
            self.pit_pos = (np.random.randint(self.grid_size), np.random.randint(self.grid_size))

    def step(self, action):
        dx, dy = self.actions[action]
        new_pos = (max(0, min(self.grid_size - 1, self.agent_pos[0] + dx)),
                   max(0, min(self.grid_size - 1, self.agent_pos[1] + dy)))
        self.agent_pos = new_pos
        if self.agent_pos == self.goal_pos:
            return 1, True
        elif self.agent_pos == self.pit_pos:
            return -1, True
        else:
            return 0, False

def sample_mdp(transitions, rewards, num_states, num_actions):
    sampled_transitions = np.zeros((num_states, num_actions, num_states))
    sampled_rewards = np.zeros((num_states, num_actions))
    for s in range(num_states):
        for a in range(num_actions):
            sampled_transitions[s, a] = np.random.dirichlet(transitions[s, a] + 1)
            sampled_rewards[s, a] = np.random.normal(rewards[s, a].mean(), rewards[s, a].std())
    return sampled_transitions, sampled_rewards

def value_iteration(transitions, rewards, discount=0.99):
    num_states, num_actions = rewards.shape
    V = np.zeros(num_states)
    while True:
        new_V = np.zeros(num_states)
        for s in range(num_states):
            new_V[s] = max(sum(transitions[s, a, s_next] * (rewards[s, a] + discount * V[s_next])
                               for s_next in range(num_states)) for a in range(num_actions))
        if np.max(np.abs(V - new_V)) < 1e-10:
            break
        V = new_V
    policy = np.zeros(num_states, dtype=int)
    for s in range(num_states):
        policy[s] = np.argmax([sum(transitions[s, a, s_next] * (rewards[s, a] + discount * V[s_next])
                                   for s_next in range(num_states)) for a in range(num_actions)])
    return policy

def psrl_agent(grid_size, num_episodes):
    num_states = grid_size * grid_size
    num_actions = 4
    transitions = np.ones((num_states, num_actions, num_states))
    rewards = np.zeros((num_states, num_actions))
    total_reward = 0

    for _ in range(num_episodes):
        env = GridWorld(grid_size)
        sampled_transitions, sampled_rewards = sample_mdp(transitions, rewards, num_states, num_actions)
        policy = value_iteration(sampled_transitions, sampled_rewards)
        done = False
        while not done:
            state = env.agent_pos[0] * grid_size + env.agent_pos[1]
            action = policy[state]
            reward, done = env.step(action)
            total_reward += reward
            next_state = env.agent_pos[0] * grid_size + env.agent_pos[1]
            transitions[state, action, next_state] += 1
            rewards[state, action] += reward
    return total_reward

