def weighted_average(obj_wgt, estimated_mean, variance):
    if isinstance(obj_wgt, (int, float)):
        return (obj_wgt * estimated_mean) + ((1 - obj_wgt) * variance)
    else:
        return sum(w * m for w, m in zip(obj_wgt, estimated_mean)) + sum((1 - w) * v for w, v in zip(obj_wgt, variance))

