class ConstructionSplitter:
    def split_locations(self, construction, start=0, stop=None):
        if stop is None:
            stop = len(construction)

        split_indices = []
        prev = start

        for i in range(start + 1, stop):
            if i - prev > 0:
                split_indices.append(i)
            if i + 1 < len(construction):
                split_indices.append(i + 1)
            prev = i + 1

        return split_indices

def solve(Clauses, Variables):
    from itertools import product

    def is_satisfied(assignment, clause):
        return any(var if var > 0 else -var not in assignment for var in clause)

    def all_satisfied(assignments, clauses):
        return all(is_satisfied(assignments, clause) for clause in clauses)

    for assignment in product([True, False], repeat=len(Variables)):
        assignment_set = {Variables[i] for i, val in enumerate(assignment) if val}
        if all_satisfied(assignment_set, Clauses):
            return assignment_set

    return set()

